scwin.f_Retrieve = async function () {
  if (!(await $c.gus.cfValidate($p, [ica_srchFromDate])) || !(await $c.gus.cfValidate($p, [ica_srchToDate]))) {
    return;
  }
  if (!$c.gus.cfIsAfterDate($p, ica_srchFromDate.getValue(), ica_srchToDate.getValue())) {
    await $c.gus.cfAlertMsg($p, MSG_CM_ERR_039);
    ica_srchFromDate.setFocus();
    return;
  }
  if (!(await $c.gus.cfValidate($p, [tb_srchCond]))) {
    return;
  }
  scwin.f_ProcessBinding();
  $c.gus.cfShowDSWaitMsg($p, gr_transWrkPlan);
  await $c.sbm.execute($p, sbm_retrieve);
};
