scwin.gr_transWrkPlan_onheaderclick = function (columnIndex, columnId) {
  let cr = ds_transWrkPlan.getRowCount();
  if (cr > 0) {
    if (columnId == "chk") {
      let allChecked = true;
      for (let i = 0; i < cr; i++) {
        if (ds_transWrkPlan.getCellData(i, "chk") != "T") {
          allChecked = false;
          break;
        }
      }
      if (!allChecked) {
        for (let i = 0; i < cr; i++) {
          ds_transWrkPlan.setCellData(i, "chk", "T");
        }
      } else {
        for (let i = 0; i < cr; i++) {
          ds_transWrkPlan.setCellData(i, "chk", "0");
        }
      }
    }
  }
};
scwin.ds_transWrkPlan_oncelldatachange = async function (info) {
  let row = info.row;
  let colid = info.colId;
  if (colid == 'qty' && !scwin.qtyEventChk) {
    scwin.wtEventChk = true;
    if (parseFloat(ds_transWrkPlan.getCellData(row, "qty")) > parseFloat(ds_transWrkPlan.getCellData(row, "oldQty"))) {
      await $c.win.alert($p, "기존수량을 추가하여 입력하였습니다.");
      ds_transWrkPlan.setCellData(row, "qty", ds_transWrkPlan.getCellData(row, "oldQty"));
      scwin.wtEventChk = false;
      return;
    }
    if (parseFloat(ds_transWrkPlan.getOriginalCellData(row, 'grossWt')) > 0) {
      if (parseFloat(ds_transWrkPlan.getOriginalCellData(row, 'qty')) == 0) {
        scwin.wtEventChk = false;
        return;
      }
      let v_wtPerQty = parseFloat(ds_transWrkPlan.getOriginalCellData(row, 'grossWt') / ds_transWrkPlan.getOriginalCellData(row, 'qty'));
      ds_transWrkPlan.setCellData(row, 'grossWt', parseFloat(ds_transWrkPlan.getCellData(row, 'qty')) * v_wtPerQty);
    }
    scwin.wtEventChk = false;
  }
  if (colid == "grossWt" && !scwin.wtEventChk) {
    if (parseFloat(ds_transWrkPlan.getCellData(row, "grossWt")) > parseFloat(ds_transWrkPlan.getCellData(row, "oldGrossWt"))) {
      await $c.win.alert($p, "기존중량을 추가하여 입력하였습니다.");
      ds_transWrkPlan.setCellData(row, "grossWt", ds_transWrkPlan.getCellData(row, "oldGrossWt"));
    }
  }
  let sumWt = 0;
  for (let i = 0; i < ds_transWrkPlan.getRowCount(); i++) {
    if (ds_transWrkPlan.getCellData(i, "chk") == "T") {
      sumWt = sumWt + parseFloat(ds_transWrkPlan.getCellData(i, "grossWt") || 0);
    }
  }
  sum_wt.setValue($c.gus.cfInsertComma($p, sumWt));
};
